import{_ as a,c as o,o as s,a1 as r}from"./chunks/framework.DILC4Csi.js";const m=JSON.parse('{"title":"Registro de Alterações: Histórico de Versões | OpenSkills","description":"Veja o histórico de alterações de versão do OpenSkills. Entenda os novos recursos, melhorias e correções de cada versão para ajudá-lo a planejar o caminho de atualização.","frontmatter":{"layout":"page","pageClass":"project-home-page","sidebar":false,"title":"Registro de Alterações: Histórico de Versões | OpenSkills","sidebarTitle":"Conheça as Últimas Alterações","subtitle":"Registro de Alterações: Histórico de Versões","description":"Veja o histórico de alterações de versão do OpenSkills. Entenda os novos recursos, melhorias e correções de cada versão para ajudá-lo a planejar o caminho de atualização.","order":6},"headers":[],"relativePath":"pt/numman-ali/openskills/changelog/index.md","filePath":"pt/numman-ali/openskills/changelog/index.md"}'),t={name:"pt/numman-ali/openskills/changelog/index.md"};function i(l,e,d,n,c,u){return s(),o("div",null,[...e[0]||(e[0]=[r('<h1 id="registro-de-alteracoes" tabindex="-1">Registro de Alterações <a class="header-anchor" href="#registro-de-alteracoes" aria-label="Permalink to &quot;Registro de Alterações&quot;">​</a></h1><p>Este capítulo registra o histórico de alterações de versão do OpenSkills, ajudando você a entender os novos recursos, melhorias e correções de cada versão.</p><h2 id="conteudo-deste-capitulo" tabindex="-1">Conteúdo deste Capítulo <a class="header-anchor" href="#conteudo-deste-capitulo" aria-label="Permalink to &quot;Conteúdo deste Capítulo&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Página</th><th>Descrição</th></tr></thead><tbody><tr><td><a href="./changelog/">Registro de Alterações</a></td><td>Registro completo de alterações de versão, incluindo novos recursos, melhorias, correções de problemas e atualizações de segurança</td></tr></tbody></table><h2 id="como-usar-o-registro-de-alteracoes" tabindex="-1">Como Usar o Registro de Alterações <a class="header-anchor" href="#como-usar-o-registro-de-alteracoes" aria-label="Permalink to &quot;Como Usar o Registro de Alterações&quot;">​</a></h2><p>O registro de alterações é organizado em ordem decrescente de número de versão (a versão mais recente fica primeiro), e cada versão contém as seguintes categorias:</p><ul><li><strong>Novidades</strong> - Recursos e comandos recém-adicionados</li><li><strong>Melhorias</strong> - Otimizações e aprimoramentos de funcionalidades existentes</li><li><strong>Correções de Problemas</strong> - Bugs corrigidos</li><li><strong>Segurança</strong> - Melhorias relacionadas à segurança</li></ul><div class="tip custom-block"><p class="custom-block-title">Recomendação de Atualização</p><p>Antes de atualizar o OpenSkills, recomendamos que você primeiro consulte o registro de alterações para entender as mudanças de versão, prestando atenção especial a:</p><ul><li><strong>Breaking Changes</strong> (alterações que quebram a compatibilidade)</li><li>Métodos de uso dos novos recursos</li><li>Situação de correções de problemas conhecidos</li></ul></div><h2 id="proximos-passos" tabindex="-1">Próximos Passos <a class="header-anchor" href="#proximos-passos" aria-label="Permalink to &quot;Próximos Passos&quot;">​</a></h2><ul><li>Consulte as <a href="./../faq/faq/">Perguntas Frequentes</a> para entender as dúvidas comuns durante o uso</li><li>Encontrou um problema? Consulte <a href="./../faq/troubleshooting/">Solução de Problemas</a> para obter soluções</li><li>Quer saber mais? Consulte a <a href="./../appendix/cli-api/">Referência da API da CLI</a> para obter documentação completa dos comandos</li></ul>',10)])])}const h=a(t,[["render",i]]);export{m as __pageData,h as default};
